use std::io::stdin;

fn main() {
    let mut input = String::new();
    stdin().read_line(&mut input).unwrap();

    let arr: Vec<i32> = input
        .split_whitespace()
        .map(|x| x.parse::<i32>().unwrap())
        .collect();

    if arr[1..].iter().min().unwrap() >= &arr[0] {
        println!("Yes");
    } else {
        println!("No");
    }
}
